import{_ as n,o as a,c as t,a2 as s}from"./chunks/framework.B72_uj9U.js";const d=JSON.parse('{"title":"TongAgents — Agentic Loop","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/tongagents/agentic-loop.md","filePath":"research/agents/tongagents/agentic-loop.md"}'),o={name:"research/agents/tongagents/agentic-loop.md"};function i(r,e,l,p,c,h){return a(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="tongagents-—-agentic-loop" tabindex="-1">TongAgents — Agentic Loop <a class="header-anchor" href="#tongagents-—-agentic-loop" aria-label="Permalink to &quot;TongAgents — Agentic Loop&quot;">​</a></h1><blockquote><p>⚠️ <strong>Limited information available.</strong> No source code or technical documentation has been published. This analysis infers loop behavior from Terminal-Bench 2.0 performance patterns and BIGAI&#39;s research background.</p></blockquote><h2 id="what-terminal-bench-requires" tabindex="-1">What Terminal-Bench Requires <a class="header-anchor" href="#what-terminal-bench-requires" aria-label="Permalink to &quot;What Terminal-Bench Requires&quot;">​</a></h2><p>Terminal-Bench 2.0 evaluates agents across 89 tasks in realistic CLI environments. To achieve 80.2% (Rank #3), TongAgents must handle:</p><ul><li><strong>Multi-step command sequences</strong> — tasks that require 5-20+ sequential shell commands</li><li><strong>Error recovery</strong> — commands that fail and require diagnosis and retry</li><li><strong>State tracking</strong> — understanding the current system state across commands</li><li><strong>Conditional execution</strong> — choosing different paths based on command output</li><li><strong>Task completion detection</strong> — knowing when a task is actually done</li></ul><p>This implies a sophisticated execution loop, not a simple prompt-then-execute cycle.</p><h2 id="inferred-loop-structure" tabindex="-1">Inferred Loop Structure <a class="header-anchor" href="#inferred-loop-structure" aria-label="Permalink to &quot;Inferred Loop Structure&quot;">​</a></h2><p>Given BIGAI&#39;s emphasis on cognitive architecture and planning, the loop likely follows a <strong>plan-execute-verify</strong> pattern:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>1. ANALYZE — Parse the task description, identify requirements</span></span>
<span class="line"><span>2. PLAN    — Generate a high-level plan with ordered steps</span></span>
<span class="line"><span>3. EXECUTE — Run the next step (shell command, file edit, etc.)</span></span>
<span class="line"><span>4. OBSERVE — Capture and interpret the output</span></span>
<span class="line"><span>5. EVALUATE — Did the step succeed? Is the plan still valid?</span></span>
<span class="line"><span>6. ADAPT   — If needed, revise the plan based on new information</span></span>
<span class="line"><span>7. VERIFY  — Check if the overall task is complete</span></span>
<span class="line"><span>8. REPEAT  — Go to step 3 if more work remains</span></span></code></pre></div><h3 id="why-plan-execute-verify" tabindex="-1">Why Plan-Execute-Verify? <a class="header-anchor" href="#why-plan-execute-verify" aria-label="Permalink to &quot;Why Plan-Execute-Verify?&quot;">​</a></h3><ul><li>BIGAI&#39;s cognitive science research emphasizes <strong>deliberative planning</strong> over reactive behavior</li><li>The high accuracy (80.2%) suggests the agent doesn&#39;t just try things randomly — it has a strategy</li><li>Terminal-Bench tasks often require understanding the <em>goal state</em> before acting</li></ul><h2 id="iteration-and-error-recovery" tabindex="-1">Iteration and Error Recovery <a class="header-anchor" href="#iteration-and-error-recovery" aria-label="Permalink to &quot;Iteration and Error Recovery&quot;">​</a></h2><p>The 80.2% score with Gemini 3.1 Pro vs ~71.9% with Claude Opus 4.6 suggests:</p><ul><li>The loop includes <strong>retry logic</strong> — when a command fails, the agent can diagnose and retry</li><li>Error recovery may depend on model reasoning quality, explaining the performance gap</li><li>The agent likely has a <strong>maximum iteration limit</strong> to prevent infinite loops on unsolvable tasks</li></ul><h2 id="multi-agent-loop-hypothesis" tabindex="-1">Multi-Agent Loop Hypothesis <a class="header-anchor" href="#multi-agent-loop-hypothesis" aria-label="Permalink to &quot;Multi-Agent Loop Hypothesis&quot;">​</a></h2><p>If TongAgents uses multiple agents (as the name suggests), the loop may involve <strong>inter-agent communication</strong>:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Orchestrator: &quot;Configure nginx with SSL&quot;</span></span>
<span class="line"><span>  → Planner: &quot;Steps: 1) install nginx, 2) generate cert, 3) configure, 4) test&quot;</span></span>
<span class="line"><span>  → Executor: runs step 1, returns output</span></span>
<span class="line"><span>  → Verifier: &quot;nginx installed successfully, proceed&quot;</span></span>
<span class="line"><span>  → Executor: runs step 2, returns error</span></span>
<span class="line"><span>  → Planner: &quot;Revise step 2: install certbot first&quot;</span></span>
<span class="line"><span>  → Executor: runs revised step, returns output</span></span>
<span class="line"><span>  → Verifier: &quot;cert generated, proceed&quot;</span></span>
<span class="line"><span>  ... continues until task complete</span></span></code></pre></div><p>This separation of concerns could explain the strong performance — each agent is focused on what it does best.</p><h2 id="what-we-don-t-know" tabindex="-1">What We Don&#39;t Know <a class="header-anchor" href="#what-we-don-t-know" aria-label="Permalink to &quot;What We Don&#39;t Know&quot;">​</a></h2><ul><li>The actual iteration limits or timeout mechanisms</li><li>How the agent handles ambiguous task descriptions</li><li>Whether there is a &quot;reflection&quot; or &quot;self-critique&quot; step (common in recent agent research)</li><li>The specific prompting strategy for each loop phase</li><li>How context is managed across loop iterations (see <a href="./context-management.html">context-management.md</a>)</li><li>Whether the loop is fixed or dynamically adapted per task type</li></ul>`,20)])])}const g=n(o,[["render",i]]);export{d as __pageData,g as default};
